package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.Node;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.TryStmt;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import java.io.File;
import java.io.IOException;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.out.println("Usage: java -jar transformer.jar <source-directory>");
            return;
        }

        String sourceDir = args[0];
        File directory = new File(sourceDir);

        // Process all Java files in the directory
        processDirectory(directory);

        System.out.println("Transformation completed successfully");
    }

    private static void processDirectory(File directory) throws IOException {
        if (!directory.exists() || !directory.isDirectory()) {
            return;
        }

        File[] files = directory.listFiles();
        if (files == null) return;

        for (File file : files) {
            if (file.isDirectory()) {
                processDirectory(file);
            } else if (file.getName().endsWith(".java")) {
                processJavaFile(file);
            }
        }
    }

    private static void processJavaFile(File file) throws IOException {
        // Parse the Java file
        CompilationUnit cu = JavaParser.parse(file);

        // Create a visitor to find and replace Jackson dependencies
        JacksonDependencyFixVisitor visitor = new JacksonDependencyFixVisitor();
        visitor.visit(cu, null);

        // Write the modified file back
        java.nio.file.Files.write(file.toPath(), cu.toString().getBytes());
    }
}

// Visitor to fix Jackson dependency issues
class JacksonDependencyFixVisitor extends VoidVisitorAdapter<Void> {

    @Override
    public void visit(com.github.javaparser.ast.ImportDeclaration importDecl, Void arg) {
        super.visit(importDecl, arg);

        // Fix Jackson dependency imports
        if (importDecl.getNameAsString().equals("com.fasterxml.jackson.core.exc.StreamWriteException")) {
            importDecl.setName("com.fasterxml.jackson.core.JsonGenerationException");
            System.out.println("Fixed Jackson exception import: " + importDecl.getNameAsString());
        }
    }

    @Override
    public void visit(TryStmt tryStmt, Void arg) {
        super.visit(tryStmt, arg);

        // Fix Jackson exception catches
        for (com.github.javaparser.ast.body.CatchClause catchClause : tryStmt.getCatchClauses()) {
            if (catchClause.getParameter().getTypeAsString().equals("com.fasterxml.jackson.core.exc.StreamWriteException")) {
                catchClause.getParameter().setType("com.fasterxml.jackson.core.JsonGenerationException");
                System.out.println("Fixed Jackson exception catch: " + catchClause.getParameter().getTypeAsString());
            }
        }
    }
}

